import pika

connection = pika.BlockingConnection(pika.ConnectionParameters('localhost', 5672))
channel = connection.channel()

# Declare a queue for task messages
queue = channel.queue_declare(queue='task_queue')

# Define a function to send task messages
def publish_message(message):
    channel.basic_publish(exchange='', routing_key=queue, body=message)

# Define a function to consume task messages
def consume_message():
    method_frame, header_frame, body = channel.basic_get(queue=queue)
    if method_frame:
        print("Received message:", body)
        # Process the message here
        channel.basic_ack(delivery_tag=method_frame.delivery_tag)
    else:
        print("No more messages")

# Start consuming task messages
channel.basic_consume(queue=queue, on_message_callback=consume_message)

# Publish a task message
publish_message('Hello from Python!')

# Close the connection
connection.close()